import{_ as a,o as t,c as i,a2 as r}from"./chunks/framework.D5wUhsuj.js";const p=JSON.parse('{"title":"Security Model","description":"","frontmatter":{},"headers":[],"relativePath":"guide/security.md","filePath":"guide/security.md"}'),o={name:"guide/security.md"};function n(s,e,l,d,c,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="security-model" tabindex="-1">Security Model <a class="header-anchor" href="#security-model" aria-label="Permalink to &quot;Security Model&quot;">​</a></h1><p>This document summarizes how AidiPanel isolates sites and limits privilege. It describes the current behavior; see the <a href="/docs/roadmap">roadmap</a> for planned hardening.</p><h2 id="site-isolation" tabindex="-1">Site Isolation <a class="header-anchor" href="#site-isolation" aria-label="Permalink to &quot;Site Isolation&quot;">​</a></h2><ul><li>Each site runs under a <strong>dedicated Linux user</strong> with a <strong>no-login shell</strong> and a <strong>locked password</strong>. Site users cannot log in over SSH.</li><li>Each site has its <strong>own PHP-FPM pool</strong> running as that user, so PHP for one site cannot read another site&#39;s files.</li><li>Web roots live under <code>/home/&lt;site-user&gt;/htdocs/&lt;domain&gt;</code> with a <code>setgid</code> directory and group-based read access for Nginx only.</li><li><strong>Site login is disabled by default.</strong> Jailed SFTP-only access can be enabled per site with a password or managed SSH keys; interactive SSH stays disabled.</li></ul><p>This is per-user process and file isolation, not container-level sandboxing.</p><h2 id="privilege-boundary" tabindex="-1">Privilege Boundary <a class="header-anchor" href="#privilege-boundary" aria-label="Permalink to &quot;Privilege Boundary&quot;">​</a></h2><ul><li>The web panel runs as the dedicated <code>aidipanel</code> system user. Nginx remains <code>www-data</code>; it can connect to the panel FastCGI socket but cannot invoke the root wrapper or read panel runtime storage.</li><li>It can only invoke <code>aidipanel-web-run</code>, a root wrapper allowed through a single narrow sudoers rule.</li><li>The wrapper enforces a fixed allowlist of subcommands; anything else is rejected.</li><li>CLI arguments are passed as argv values and never interpolated into shell strings.</li></ul><h2 id="guarded-deletion" tabindex="-1">Guarded Deletion <a class="header-anchor" href="#guarded-deletion" aria-label="Permalink to &quot;Guarded Deletion&quot;">​</a></h2><p>Purge-delete (remove the Linux user, home, and all site resources) only proceeds when the <code>/home/&lt;site-user&gt;/.aidipanel-managed</code> marker:</p><ul><li>exists and is owned <code>root:root</code>,</li><li>is not writable by the site user,</li><li>and matches the domain and user the panel resolved from its database.</li></ul><p>If any check fails, the operation is refused and nothing is removed. This prevents the panel from ever deleting an account or directory it did not create.</p><h2 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h2><ul><li><strong>UFW</strong> preserves existing rules, opens detected/current SSH ports, HTTP (80), HTTPS (443), and the configured panel port (8443 by default).</li><li><strong>Fail2ban</strong> is configured against brute-force attempts.</li><li>The panel listens on its own HTTPS port with a self-signed certificate by default; user sites use Let&#39;s Encrypt.</li></ul><h2 id="tls" tabindex="-1">TLS <a class="header-anchor" href="#tls" aria-label="Permalink to &quot;TLS&quot;">​</a></h2><ul><li>Let&#39;s Encrypt certificates via Certbot, with automatic renewal.</li><li>TLS 1.2/1.3 and OCSP stapling in managed HTTPS vhosts. HSTS is opt-in per site and should be enabled only after a trusted certificate is active.</li></ul><h2 id="application" tabindex="-1">Application <a class="header-anchor" href="#application" aria-label="Permalink to &quot;Application&quot;">​</a></h2><ul><li>CSRF protection on state-changing requests.</li><li>Session hardening and a brute-force throttle on panel login.</li><li>Admin, manager, and client roles are enforced server-side, with per-site assignment for client accounts.</li><li>Optional TOTP two-factor authentication includes one-time recovery codes.</li><li>Credentials are generated randomly at install and stored in <code>/opt/aidipanel/credentials.conf</code> (mode 600).</li><li><code>self:update</code> verifies the CLI and panel release assets against the published <code>SHA256SUMS</code> before activation and preserves existing users and runtime data.</li></ul><h2 id="reporting" tabindex="-1">Reporting <a class="header-anchor" href="#reporting" aria-label="Permalink to &quot;Reporting&quot;">​</a></h2><p>If you find a security issue, please report it privately through the repository&#39;s security advisory feature rather than a public issue.</p>',19)])])}const g=a(o,[["render",n]]);export{p as __pageData,g as default};
